{
  "pattern": {
    "summary": "Fold compares of a value with a monotonic toward-zero quotient/shift of itself into a compare against zero.",
    "motivation_from_example": {
      "input": "%q = sdiv X, C ; %cmp = icmp slt %q, X",
      "condition": "C is a constant integer > 1",
      "result": "%cmp == icmp sgt X, 0"
    },
    "general_form": {
      "shape": "%y = OP X, K ; %cmp = icmp PRED %y, X",
      "rewrite": "%cmp -> icmp swap(PRED) X, 0",
      "note": "swap(PRED) is the predicate obtained by swapping operands of the compare."
    },
    "supported_ops": [
      {
        "op": "udiv",
        "k_condition": "constant integer C > 1",
        "predicates": "unsigned/equality predicates where comparing udiv result to the dividend is well-formed under operand types; practically all icmp preds are syntactically valid, but InstCombine should preserve signedness conventions of the original predicate family."
      },
      {
        "op": "sdiv",
        "k_condition": "constant integer C > 1",
        "predicates": "signed predicates only",
        "reason": "For positive divisors > 1, signed division rounds toward zero and moves X toward zero."
      },
      {
        "op": "lshr",
        "k_condition": "constant shift Sh != 0",
        "predicates": "naturally useful for unsigned/equality predicates"
      },
      {
        "op": "ashr",
        "k_condition": "constant shift Sh != 0",
        "predicates": "signed slt/sge only",
        "reason": "Arithmetic right shift preserves sign and moves values toward -1/0; only certain signed predicates reduce to a zero sign test."
      }
    ],
    "semantic_intuition": [
      "For nontrivial udiv/lshr, the result is never greater than the original in the unsigned order; it equals the original only when X is zero.",
      "For sdiv by a positive constant > 1, the result has the same sign as X or is zero, and has magnitude no greater than |X|; comparing quotient to X reduces to asking whether X is positive, negative, or zero depending on the predicate direction.",
      "For ashr by nonzero, negative values remain <= their shifted result in signed order, while nonnegative values move toward zero; this supports slt/sge folds to a sign check."
    ],
    "implementation_notes": [
      "This naturally belongs in foldICmpCommutative() or equivalent canonical compare-folding logic.",
      "The fold should work for scalar and vector integer types, including splat or per-lane constants where legality/semantics are lane-wise.",
      "Only the icmp should be simplified if the div/shift has other uses.",
      "Do not match trivial divisors/shifts: udiv/sdiv by 1 and shifts by 0.",
      "For sdiv, require constant divisor > 1; do not apply to divisor == -1 or other negative divisors.",
      "For ashr, restrict to signed predicates proven valid, notably slt/sge."
    ]
  },
